大家好，我是程普，我整理了 NEXTY.DEV 模板的通用文档和非公开资源，以专栏形式发布到哥飞社群网站，希望能帮助到大家。
NEXTY.DEV 向哥飞社群提供骨折价，想购买的朋友加我微信（bigye_chengpu）获取专属优惠码再下单。
因为使用 Vercel 等第三方平台部署的成本越来越高，所以有不少人开始购买 VPS 自部署，而自部署的开发者中，又有不少选择使用 Github Actons 自动构建镜像。
使用 GitHub Actions 构建镜像最麻烦的一个步骤是，要手动在 GitHub 上配置环境变量。如果你的项目有几十个环境变量，一顿操作下来要花10-20分钟，而且有可能复制出错。
如果有一种方式，可以自动更新 GitHub Actions 的环境变量，岂不是可以省下大量时间？
实际上，GitHub Cli 支持通过命令更新环境变量，那么就可以写一个自动操作脚本来做这件事了。NEXTY.DEV 模板就内置了这样的脚本，现在我把方法分享出来。
你只需要输入一条命令，等待5-10秒就能完成几十个环境变量的配置，而且完全不用担心复制出错。
脚本介绍
两个脚本内容放在文末，这里先介绍下它们的作用：
同步脚本 sync-env-to-github.mjs：自动解析本地 .env 文件，自动分类，将 NEXT_PUBLIC_* 开头的变量创建为 GitHub Variables（公开可见），其他变量创建为 GitHub Secrets（加密存储）
清理脚本 clear-env-from-github.mjs：一键清理 GitHub 上的环境变量
两个脚本都针对环境变量的不同写法和存在的符号，能够把非必要符合都自动删除，保证填充的环境变量正确；而且支持并发处理，处理几十个环境变量只需要5-10秒。
快速开始
第一步：安装 GitHub CLI
MacOS 用户：
brew install gh
Windows 用户：
# 使用 winget
winget install --id GitHub.cli

# 或使用 scoop
scoop install gh
第二步：登录 GitHub
gh auth login
按照交互式提示完成登录，建议选择：
登录方式：GitHub.com
认证协议：HTTPS 或 SSH（根据你的偏好）
认证方式：Login with a web browser（最简单）
第三步：确保仓库权限
重要：你需要对目标仓库拥有 Admin 权限才能创建和管理 Secrets/Variables。
检查你的权限：
访问你的 GitHub 仓库
进入 Settings → Secrets and variables → Actions
如果能看到 "New repository secret" 按钮，说明权限正常
使用方法
在你的 package.json 添加快捷命令：
{
  "scripts": {
    "env:sync": "node scripts/sync-env-to-github.mjs",
    "env:clear": "node scripts/clear-env-from-github.mjs"
  }
}
同步流程：
# 1. （可选但推荐）先清理旧的环境变量
npm run env:clear

# 2. 同步最新的环境变量
npm run env:sync
执行后你会看到类似这样的输出：
📂 Reading from: .env
🔗 Target repo: your-name/your-repo
⚡ Concurrency: 5

🚀 Processing 44 items...

✅ Done in 10.9s!
   📦 Variables created: 19
   🔐 Secrets created: 25
   ⏭️  Skipped: 9
脚本分享
sync-env-to-github.mjs
#!/usr/bin/env node

/**
 * Sync .env to GitHub Actions Secrets/Variables
 *
 * Usage: node scripts/sync-env-to-github.mjs [.env file path] [repo] [options]
 *
 * Options:
 *   --concurrency=N   Number of parallel operations (default: 5)
 *
 * This script reads your .env file and creates:
 * - GitHub Variables for NEXT_PUBLIC_* variables
 * - GitHub Secrets for all other variables
 *
 * Prerequisites:
 * - GitHub CLI (gh) installed and authenticated
 * - Run: gh auth login
 */

import { exec, execSync } from "child_process";
import { existsSync, readFileSync } from "fs";
import { resolve } from "path";
import { promisify } from "util";

const execAsync = promisify(exec);

// ANSI colors for terminal output
const colors = {
  reset: "\x1b[0m",
  red: "\x1b[31m",
  green: "\x1b[32m",
  yellow: "\x1b[33m",
  blue: "\x1b[34m",
  cyan: "\x1b[36m",
};

const log = {
  error: (msg) => console.log(`${colors.red}❌ ${msg}${colors.reset}`),
  success: (msg) => console.log(`${colors.green}✅ ${msg}${colors.reset}`),
  info: (msg) => console.log(`${colors.cyan}${msg}${colors.reset}`),
  secret: (msg) => console.log(`${colors.blue}🔐 ${msg}${colors.reset}`),
  variable: (msg) => console.log(`${colors.green}📦 ${msg}${colors.reset}`),
  skip: (msg) => console.log(`${colors.yellow}⏭️  ${msg}${colors.reset}`),
  warn: (msg) => console.log(`${colors.yellow}   ⚠️  ${msg}${colors.reset}`),
};

// Check if gh CLI is installed
function checkGhCli() {
  try {
    execSync("gh --version", { stdio: "pipe" });
    return true;
  } catch {
    return false;
  }
}

// Check if authenticated
function checkAuth() {
  try {
    execSync("gh auth status", { stdio: "pipe" });
    return true;
  } catch {
    return false;
  }
}

// Get current repo
function getRepo() {
  try {
    const result = execSync(
      "gh repo view --json nameWithOwner -q .nameWithOwner",
      {
        encoding: "utf-8",
        stdio: ["pipe", "pipe", "pipe"],
      }
    );
    return result.trim();
  } catch {
    return null;
  }
}

// Set a secret (async)
async function setSecretAsync(key, value, repo) {
  return new Promise((resolve) => {
    const child = exec(
      `gh secret set "${key}" --repo "${repo}"`,
      (error) => {
        if (error) {
          resolve({ success: false, key, type: "secret" });
        } else {
          resolve({ success: true, key, type: "secret" });
        }
      }
    );
    child.stdin.write(value);
    child.stdin.end();
  });
}

// Set a variable (async)
async function setVariableAsync(key, value, repo) {
  try {
    const escapedValue = value.replace(/"/g, '\\"');
    await execAsync(
      `gh variable set "${key}" --body "${escapedValue}" --repo "${repo}"`
    );
    return { success: true, key, type: "variable" };
  } catch {
    return { success: false, key, type: "variable" };
  }
}

// Parse .env file
function parseEnvFile(filePath) {
  const content = readFileSync(filePath, "utf-8");
  const entries = [];

  for (const line of content.split("\n")) {
    const trimmed = line.trim();

    // Skip empty lines and comments
    if (!trimmed || trimmed.startsWith("#")) {
      continue;
    }

    // Match KEY=VALUE pattern
    const match = trimmed.match(/^([A-Za-z_][A-Za-z0-9_]*)=(.*)$/);
    if (match) {
      let [, key, value] = match;

      // First, trim the value and handle \r (Windows line endings)
      value = value.trim().replace(/\r$/, "");

      // Check if value starts with quote
      if (value.startsWith('"') || value.startsWith("'")) {
        const quote = value[0];
        // Find the closing quote
        const endQuoteIndex = value.indexOf(quote, 1);
        if (endQuoteIndex !== -1) {
          // Extract value between quotes
          value = value.substring(1, endQuoteIndex);
        }
      } else {
        // Remove inline comments (unquoted values only)
        // Match: value # comment
        const commentIndex = value.indexOf(" #");
        if (commentIndex !== -1) {
          value = value.substring(0, commentIndex);
        }
        value = value.trim();
      }

      entries.push({ key, value });
    }
  }

  return entries;
}

// Process items in batches with concurrency limit
async function processBatch(items, concurrency, processFn) {
  const results = [];
  const executing = new Set();

  for (const item of items) {
    const promise = processFn(item).then((result) => {
      executing.delete(promise);
      return result;
    });
    executing.add(promise);
    results.push(promise);

    if (executing.size >= concurrency) {
      await Promise.race(executing);
    }
  }

  return Promise.all(results);
}

// Parse command line arguments
function parseArgs(args) {
  const options = {
    envFile: ".env",
    repo: null,
    concurrency: 5,
  };

  for (const arg of args) {
    if (arg.startsWith("--concurrency=")) {
      options.concurrency = parseInt(arg.split("=")[1], 10) || 5;
    } else if (arg.startsWith("--")) {
      // ignore unknown flags
    } else if (!options.envFile || options.envFile === ".env") {
      if (arg.includes("/") && !arg.includes(".env")) {
        options.repo = arg;
      } else {
        options.envFile = arg;
      }
    } else {
      options.repo = arg;
    }
  }

  return options;
}

// Main function
async function main() {
  const args = process.argv.slice(2);
  const options = parseArgs(args);
  const envPath = resolve(process.cwd(), options.envFile);

  // Preflight checks
  if (!checkGhCli()) {
    log.error("GitHub CLI (gh) is not installed");
    console.log("   Install it from: https://cli.github.com/");
    process.exit(1);
  }

  if (!checkAuth()) {
    log.error("Not logged in to GitHub CLI");
    console.log("   Run: gh auth login");
    process.exit(1);
  }

  if (!existsSync(envPath)) {
    log.error(`File not found: ${envPath}`);
    process.exit(1);
  }

  const repo = options.repo || getRepo();
  if (!repo) {
    log.error(
      "Could not detect repository. Please specify: node sync-env-to-github.mjs .env owner/repo"
    );
    process.exit(1);
  }

  log.info(`📂 Reading from: ${options.envFile}`);
  log.info(`🔗 Target repo: ${repo}`);
  log.info(`⚡ Concurrency: ${options.concurrency}`);
  console.log("");

  const entries = parseEnvFile(envPath);

  // Filter out empty values and prepare tasks
  const tasks = [];
  let skippedCount = 0;

  for (const { key, value } of entries) {
    if (!value) {
      log.skip(`Skipping ${key} (empty value)`);
      skippedCount++;
      continue;
    }

    if (key.startsWith("NEXT_PUBLIC_")) {
      tasks.push({ key, value, type: "variable" });
    } else {
      tasks.push({ key, value, type: "secret" });
    }
  }

  console.log("");
  log.info(`🚀 Processing ${tasks.length} items...`);
  console.log("");

  // Process all tasks concurrently
  const startTime = Date.now();
  const results = await processBatch(
    tasks,
    options.concurrency,
    async (task) => {
      if (task.type === "variable") {
        log.variable(`Setting variable: ${task.key}`);
        return setVariableAsync(task.key, task.value, repo);
      } else {
        log.secret(`Setting secret: ${task.key}`);
        return setSecretAsync(task.key, task.value, repo);
      }
    }
  );

  const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);

  // Count results
  let varsCount = 0;
  let secretsCount = 0;
  let failedCount = 0;

  for (const result of results) {
    if (result.success) {
      if (result.type === "variable") varsCount++;
      else secretsCount++;
    } else {
      log.warn(`Failed to set ${result.type} ${result.key}`);
      failedCount++;
    }
  }

  console.log("");
  log.success(`Done in ${elapsed}s!`);
  console.log(`   📦 Variables created: ${varsCount}`);
  console.log(`   🔐 Secrets created: ${secretsCount}`);
  console.log(`   ⏭️  Skipped: ${skippedCount}`);
  if (failedCount > 0) {
    console.log(`   ❌ Failed: ${failedCount}`);
  }
}

main().catch((err) => {
  log.error(err.message);
  process.exit(1);
});

clear-env-from-github.mjs
#!/usr/bin/env node

/**
 * Clear .env variables from GitHub Actions Secrets/Variables
 *
 * Usage: node scripts/clear-env-from-github.mjs [.env file path] [repo] [options]
 *
 * Options:
 *   --yes, -y         Skip confirmation prompt
 *   --concurrency=N   Number of parallel operations (default: 5)
 *
 * This script reads your .env file and deletes:
 * - GitHub Variables for NEXT_PUBLIC_* variables
 * - GitHub Secrets for all other variables
 *
 * Prerequisites:
 * - GitHub CLI (gh) installed and authenticated
 * - Run: gh auth login
 */

import { exec, execSync } from "child_process";
import { existsSync, readFileSync } from "fs";
import { createInterface } from "readline";
import { resolve } from "path";
import { promisify } from "util";

const execAsync = promisify(exec);

// ANSI colors for terminal output
const colors = {
  reset: "\x1b[0m",
  red: "\x1b[31m",
  green: "\x1b[32m",
  yellow: "\x1b[33m",
  blue: "\x1b[34m",
  cyan: "\x1b[36m",
  bold: "\x1b[1m",
};

const log = {
  error: (msg) => console.log(`${colors.red}❌ ${msg}${colors.reset}`),
  success: (msg) => console.log(`${colors.green}✅ ${msg}${colors.reset}`),
  info: (msg) => console.log(`${colors.cyan}${msg}${colors.reset}`),
  secret: (msg) => console.log(`${colors.blue}🔐 ${msg}${colors.reset}`),
  variable: (msg) => console.log(`${colors.green}📦 ${msg}${colors.reset}`),
  skip: (msg) => console.log(`${colors.yellow}⏭️  ${msg}${colors.reset}`),
  warn: (msg) => console.log(`${colors.yellow}   ⚠️  ${msg}${colors.reset}`),
  danger: (msg) =>
    console.log(`${colors.bold}${colors.red}⚠️  ${msg}${colors.reset}`),
};

// Prompt user for confirmation
function confirm(question) {
  return new Promise((resolve) => {
    const rl = createInterface({
      input: process.stdin,
      output: process.stdout,
    });

    rl.question(question, (answer) => {
      rl.close();
      resolve(answer.toLowerCase() === "y" || answer.toLowerCase() === "yes");
    });
  });
}

// Check if gh CLI is installed
function checkGhCli() {
  try {
    execSync("gh --version", { stdio: "pipe" });
    return true;
  } catch {
    return false;
  }
}

// Check if authenticated
function checkAuth() {
  try {
    execSync("gh auth status", { stdio: "pipe" });
    return true;
  } catch {
    return false;
  }
}

// Get current repo
function getRepo() {
  try {
    const result = execSync(
      "gh repo view --json nameWithOwner -q .nameWithOwner",
      {
        encoding: "utf-8",
        stdio: ["pipe", "pipe", "pipe"],
      }
    );
    return result.trim();
  } catch {
    return null;
  }
}

// Delete a secret (async)
async function deleteSecretAsync(key, repo) {
  try {
    await execAsync(`gh secret delete "${key}" --repo "${repo}"`);
    return { success: true, key, type: "secret" };
  } catch {
    return { success: false, key, type: "secret" };
  }
}

// Delete a variable (async)
async function deleteVariableAsync(key, repo) {
  try {
    await execAsync(`gh variable delete "${key}" --repo "${repo}"`);
    return { success: true, key, type: "variable" };
  } catch {
    return { success: false, key, type: "variable" };
  }
}

// Parse .env file
function parseEnvFile(filePath) {
  const content = readFileSync(filePath, "utf-8");
  const entries = [];

  for (const line of content.split("\n")) {
    const trimmed = line.trim();

    // Skip empty lines and comments
    if (!trimmed || trimmed.startsWith("#")) {
      continue;
    }

    // Match KEY=VALUE pattern
    const match = trimmed.match(/^([A-Za-z_][A-Za-z0-9_]*)=(.*)$/);
    if (match) {
      const [, key] = match;
      entries.push({ key });
    }
  }

  return entries;
}

// Process items in batches with concurrency limit
async function processBatch(items, concurrency, processFn) {
  const results = [];
  const executing = new Set();

  for (const item of items) {
    const promise = processFn(item).then((result) => {
      executing.delete(promise);
      return result;
    });
    executing.add(promise);
    results.push(promise);

    if (executing.size >= concurrency) {
      await Promise.race(executing);
    }
  }

  return Promise.all(results);
}

// Parse command line arguments
function parseArgs(args) {
  const options = {
    envFile: ".env",
    repo: null,
    skipConfirm: false,
    concurrency: 5,
  };

  for (const arg of args) {
    if (arg === "--yes" || arg === "-y") {
      options.skipConfirm = true;
    } else if (arg.startsWith("--concurrency=")) {
      options.concurrency = parseInt(arg.split("=")[1], 10) || 5;
    } else if (arg.startsWith("--")) {
      // ignore unknown flags
    } else if (!options.envFile || options.envFile === ".env") {
      if (arg.includes("/") && !arg.includes(".env")) {
        options.repo = arg;
      } else {
        options.envFile = arg;
      }
    } else {
      options.repo = arg;
    }
  }

  return options;
}

// Main function
async function main() {
  const args = process.argv.slice(2);
  const options = parseArgs(args);
  const envPath = resolve(process.cwd(), options.envFile);

  // Preflight checks
  if (!checkGhCli()) {
    log.error("GitHub CLI (gh) is not installed");
    console.log("   Install it from: https://cli.github.com/");
    process.exit(1);
  }

  if (!checkAuth()) {
    log.error("Not logged in to GitHub CLI");
    console.log("   Run: gh auth login");
    process.exit(1);
  }

  if (!existsSync(envPath)) {
    log.error(`File not found: ${envPath}`);
    process.exit(1);
  }

  const repo = options.repo || getRepo();
  if (!repo) {
    log.error(
      "Could not detect repository. Please specify: node clear-env-from-github.mjs .env owner/repo"
    );
    process.exit(1);
  }

  const entries = parseEnvFile(envPath);

  // Prepare tasks
  const variables = entries.filter((e) => e.key.startsWith("NEXT_PUBLIC_"));
  const secrets = entries.filter((e) => !e.key.startsWith("NEXT_PUBLIC_"));

  log.info(`📂 Reading from: ${options.envFile}`);
  log.info(`🔗 Target repo: ${repo}`);
  console.log("");

  // Show what will be deleted
  log.danger("This will DELETE the following from GitHub Actions:");
  console.log("");
  console.log(`   📦 ${variables.length} Variables:`);
  variables.slice(0, 5).forEach((v) => console.log(`      - ${v.key}`));
  if (variables.length > 5)
    console.log(`      ... and ${variables.length - 5} more`);
  console.log("");
  console.log(`   🔐 ${secrets.length} Secrets:`);
  secrets.slice(0, 5).forEach((s) => console.log(`      - ${s.key}`));
  if (secrets.length > 5)
    console.log(`      ... and ${secrets.length - 5} more`);
  console.log("");

  // Confirm deletion
  if (!options.skipConfirm) {
    const confirmed = await confirm(
      `${colors.yellow}Are you sure you want to delete these? (y/N): ${colors.reset}`
    );
    if (!confirmed) {
      log.info("❌ Cancelled");
      process.exit(0);
    }
    console.log("");
  }

  log.info(`⚡ Concurrency: ${options.concurrency}`);
  log.info(`🗑️  Deleting...`);
  console.log("");

  // Prepare all tasks
  const tasks = [
    ...variables.map((v) => ({ key: v.key, type: "variable" })),
    ...secrets.map((s) => ({ key: s.key, type: "secret" })),
  ];

  // Process all tasks concurrently
  const startTime = Date.now();
  const results = await processBatch(
    tasks,
    options.concurrency,
    async (task) => {
      if (task.type === "variable") {
        log.variable(`Deleting variable: ${task.key}`);
        return deleteVariableAsync(task.key, repo);
      } else {
        log.secret(`Deleting secret: ${task.key}`);
        return deleteSecretAsync(task.key, repo);
      }
    }
  );

  const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);

  // Count results
  let varsCount = 0;
  let secretsCount = 0;
  let notFoundCount = 0;

  for (const result of results) {
    if (result.success) {
      if (result.type === "variable") varsCount++;
      else secretsCount++;
    } else {
      log.warn(`${result.key} not found or failed to delete`);
      notFoundCount++;
    }
  }

  console.log("");
  log.success(`Done in ${elapsed}s!`);
  console.log(`   📦 Variables deleted: ${varsCount}`);
  console.log(`   🔐 Secrets deleted: ${secretsCount}`);
  console.log(`   ⏭️  Not found/failed: ${notFoundCount}`);
}

main().catch((err) => {
  log.error(err.message);
  process.exit(1);
});

