                /* 隐藏原始统计信息 */
                #result-stats {
                    display: none !important;
                }
            `;
            document.head.appendChild(style);

            // 插入到搜索结果区域的顶部
            const searchResults = document.querySelector('#search') ||
                                 document.querySelector('main') ||
