/* Reset and base styles */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Open Sans', 'Helvetica Neue', sans-serif;
    line-height: 1.6;
    color: #333;
    max-width: 1200px;
    margin: 0 auto;
    padding: 1rem;
}

/* Header */
header {
    background-color: #f4f4f4;
    padding: 1rem;
    margin-bottom: 2rem;
}

h1 {
    color: #2c3e50;
    text-align: center;
}

nav ul {
    display: flex;
    justify-content: center;
    list-style: none;
    margin-top: 1rem;
}

nav ul li {
    margin: 0 1rem;
}

nav ul li a {
    text-decoration: none;
    color: #3498db;
    font-weight: bold;
}

/* Sections */
section {
    margin-bottom: 2rem;
    padding: 1rem;
    background-color: #ffffff;
    border-radius: 5px;
    box-shadow: 0 2px 5px rgba(0,0,0,0.1);
}

h2 {
    color: #2c3e50;
    border-bottom: 2px solid #3498db;
    padding-bottom: 0.5rem;
    margin-bottom: 1rem;
}

h3 {
    color: #34495e;
    margin-bottom: 0.5rem;
}

/* Features */
.feature {
    margin-bottom: 1rem;
}

.feature ul {
    padding-left: 2rem;
}

/* Recipes */
.recipe-preview ul {
    display: flex;
    flex-wrap: wrap;
    list-style: none;
}

.recipe-preview ul li {
    background-color: #3498db;
    color: white;
    margin: 0.5rem;
    padding: 0.5rem 1rem;
    border-radius: 3px;
}

/* Footer */
footer {
    text-align: center;
    padding: 1rem;
    background-color: #f4f4f4;
}

footer nav a {
    margin: 0 1rem;
    color: #7f8c8d;
    text-decoration: none;
}

/* Responsive Design */
@media screen and (max-width: 768px) {
    nav ul {
        flex-direction: column;
        align-items: center;
    }

    nav ul li {
        margin: 0.5rem 0;
    }

    .recipe-preview ul {
        justify-content: center;
    }
}

/* Accessibility Improvements */
a:focus, button:focus {
    outline: 3px solid #3498db;
    outline-offset: 2px;
}

/* Print Styles */
@media print {
    body {
        font-size: 12pt;
        max-width: none;
    }

    header, footer {
        display: none;
    }
}
