🧪 使用流程 安装油猴插件：Tampermonkey
创建一个基于快捷键Ctrl+Shift+V的新脚本(可自行修改），插入自定义逻辑：
✨ 脚本片段示意
// ==UserScript==
// @name         SimilarWeb 一键复制关键词 (快捷键+顶部通知)
// @namespace    http://tampermonkey.net/
// @version      5.1
// @description  按 Ctrl+Shift+V 或点击油猴菜单命令来复制选中的（或全部）关键词。成功后在页面顶部显示优雅的通知。
// @author       AI-Enhanced & You & 峻菁
// @match        https://pro.similarweb.com/*
// @match        https://sim.3ue.com/*
// @grant        GM_setClipboard
// @grant        GM_registerMenuCommand
// @grant        GM_addStyle
// ==/UserScript==

(function() {
    'use strict';

    /**
     * 在页面顶部显示一个自定义的通知条
     * @param {string} message - 要显示的消息
     * @param {string} type - 通知类型 ('success' 或 'error')
     */
    function showTopNotification(message, type = 'success') {
        // 移除可能存在的旧通知
        const oldNotification = document.getElementById('sw-custom-notification');
        if (oldNotification) {
            oldNotification.remove();
        }

        const notification = document.createElement('div');
        notification.id = 'sw-custom-notification';
        notification.textContent = message;

        const backgroundColor = type === 'success' ? '#28a745' : '#dc3545'; // 绿色成功，红色失败
        notification.style.cssText = `
            position: fixed;
            top: -50px; /* 初始位置在屏幕外 */
            left: 50%;
            transform: translateX(-50%);
            background-color: ${backgroundColor};
            color: white;
            padding: 12px 25px;
            border-radius: 8px;
            box-shadow: 0 4px 8px rgba(0,0,0,0.2);
            font-size: 16px;
            font-weight: bold;
            z-index: 99999;
            transition: top 0.5s ease-in-out;
            white-space: nowrap;
        `;

        document.body.appendChild(notification);

        // 延迟一小段时间，让元素渲染出来，再触发滑入动画
        setTimeout(() => {
            notification.style.top = '20px';
        }, 50);

        // 3秒后自动滑出并移除
        setTimeout(() => {
            notification.style.top = '-50px';
            setTimeout(() => {
                if(notification.parentElement) {
                    notification.parentElement.removeChild(notification);
                }
            }, 500); // 等动画结束后再移除DOM
        }, 3000);
    }

    /**
     * 核心功能：提取并复制关键词到剪贴板
     */
    async function copyKeywords() {
        console.log('触发关键词复制操作...');

        const tableContainer = document.querySelector('.swReactTable-scrollable, .KeywordsGenerator-table'); // 兼容两种可能的表格容器
        if (!tableContainer) {
            showTopNotification('错误: 未找到数据表格!', 'error');
            console.error('未能找到表格容器。');
            return;
        }

        const checkedRowIndexes = new Set();
        document.querySelectorAll('div[data-automation-icon-name="checkbox-on"]').forEach(icon => {
            const cell = icon.closest('[data-table-row]');
            if (cell) checkedRowIndexes.add(cell.dataset.tableRow);
        });

        let extractionMode = '';
        if (checkedRowIndexes.size === 0) {
            extractionMode = '所有可见行';
            console.log("没有勾选行，将提取所有可见行...");
            tableContainer.querySelectorAll('.swReactTableCell[data-table-col="0"]').forEach(cell => {
                if (cell.dataset.tableRow) {
                    checkedRowIndexes.add(cell.dataset.tableRow);
                }
            });
        } else {
            extractionMode = '已勾选行';
            console.log(`检测到 ${checkedRowIndexes.size} 个勾选行。`);
        }

        if (checkedRowIndexes.size === 0) {
            showTopNotification('错误: 未找到任何数据行!', 'error');
            return;
        }

        const keywords = [];
        const sortedIndexes = Array.from(checkedRowIndexes).sort((a, b) => parseInt(a) - parseInt(b));

        sortedIndexes.forEach(index => {
            const xpath = `//div[@data-table-row="${index}"]//span[contains(@class, "search-keyword")]/a`;
            const keywordElement = document.evaluate(xpath, document, null, XPathResult.FIRST_ORDERED_NODE_TYPE, null).singleNodeValue;
            if (keywordElement) {
                keywords.push(keywordElement.innerText.trim());
            }
        });

        console.log("提取到的关键词列表:", keywords);

        if (keywords.length === 0) {
            showTopNotification('提取失败: 未能获取到关键词文本。', 'error');
        } else {
            const textToCopy = keywords.join('\n');
            GM_setClipboard(textToCopy, 'text');
            const message = `成功复制 ${keywords.length} 个关键词 (${extractionMode})！`;
            showTopNotification(message, 'success');
            console.log(message);
        }
    }

    // --- 注册菜单命令 ---
    GM_registerMenuCommand('复制关键词 (选中/全部)', copyKeywords, 'v');

    // --- 注册快捷键 ---
    document.addEventListener('keydown', function(event) {
        // 快捷键: Ctrl + Shift + V
        if (event.ctrlKey && event.shiftKey && event.key.toLowerCase() === 'v') {
            event.preventDefault(); // 阻止浏览器默认行为 (例如某些编辑器的“无格式粘贴”)
            copyKeywords();
        }
    });

    console.log('SimilarWeb 快捷键/菜单脚本已加载。按 [Ctrl+Shift+V] 或点击油猴菜单执行复制。');

})();
（⚠️ 不同版本 Similarweb 页面结构可能不同，需根据 DOM 调整选择器）
