import type React from "react";
import { cn } from "@/lib/utils";
import { GoogleAdSenseUnit } from "./google-adsense-unit";

export interface AdContainerProps {
  /** ad unit id */
  adUnitId: string;
  /** ad size preset */
  size?:
    | "banner"
    | "leaderboard"
    | "large-leaderboard"
    | "large-rectangle"
    | "medium-rectangle"
    | "square"
    | "vertical"
    | "large-vertical"
    | "mobile-banner"
    | "custom";
  /** custom width (only when size="custom") */
  width?: number | string;
  /** custom height (only when size="custom") */
  height?: number | string;
  /** whether to enable responsive ad */
  responsive?: boolean;
  /** ad position */
  position?: "in-article" | "in-feed" | "matched-content";
  /** custom class name */
  className?: string;
  /** ad class name */
  adClassName?: string;
  /** ad container style */
  containerStyle?: "card" | "inline" | "floating" | "sticky" | "none";
  /** ad label text */
  adLabel?: string;
  /** children */
  children?: React.ReactNode;
}

/**
 * ad unit container component
 *
 * provide multiple preset size and style options for ad unit
 */
export function AdUnitContainer({
  adUnitId,
  size = "leaderboard",
  width,
  height,
  responsive = true,
  position,
  className,
  adClassName,
  containerStyle = "inline",
  adLabel = "Ad",
